import java.util.Scanner;

public class SecureBuffer {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.print("Enter your name: ");
        String name = scanner.nextLine();

        // Allocate a buffer based on the length of user input
        byte[] userInputBytes = name.getBytes();
        int bufferSize = Math.min(userInputBytes.length, 10); // Limit buffer size to 10 bytes
        byte[] buffer = new byte[bufferSize];

        // Copying user input into the buffer with bounds checking
        System.arraycopy(userInputBytes, 0, buffer, 0, bufferSize);

        System.out.println("Hello, " + new String(buffer));
    }
}

